external_knowledge:
- Stable isotopes are non-radioactive, meaning they do not undergo radioactive decay; 
- Abundance refers to the percentage of a particular isotope present in a naturally occurring sample; 
- Half-life is the time required for half of the atoms in a sample to decay; 
- β- (beta minus) radiation is a type of radioactive decay where a neutron is converted into a proton and an electron; 
- Branching ratio refers to the likelihood of a particular decay mode occurring.

sql:
SELECT symbol
FROM isotopes
ORDER BY symbol;

SELECT name
FROM isotopes
WHERE discovery_year > 1930 AND isotope_state = 'radioactive';

SELECT notation
FROM nuclide
WHERE isotope_state = 'radioactive' AND isotope_type = 'synthetic';

SELECT notation
FROM nuclide
WHERE nuclide_id = 1;

SELECT COUNT(*) AS stable_isotope_count
FROM isotopes
WHERE isotope_state = 'stable';

SELECT MAX(abundance) AS max_abundance
FROM abundances
WHERE abundance_type = 'natural';

SELECT abundance
FROM abundances
WHERE isotope_id = (SELECT isotope_id FROM isotopes WHERE symbol = 'Os');

SELECT symbol
FROM isotopes
ORDER BY symbol;

SELECT AVG(decay_energy) AS average_decay_energy
FROM decay_energies
WHERE unit = 'MeV';

SELECT MAX(half_life) AS max_half_life
FROM half_lives
WHERE nuclide_id = 0;
